/**
 * Programmatic audit of ALL documents generated by the latest PLAYWRIGHT QA
 * company run. For each doc in the company's S3 folder, download and check:
 *   - DOCX is structurally valid (opens as a ZIP, has word/document.xml)
 *   - Font: 0 Arial references in any XML part
 *   - Generic: no unresolved {{placeholder}} left in body text
 *   - No bare "County, Florida" (only applies to agreement)
 *   - No 'th or such' artifact (agreement-specific)
 *   - Company name "PLAYWRIGHT QA" substituted somewhere (sanity check)
 *
 * Finds the newest PLAYWRIGHT company folder automatically.
 */
import { execSync } from 'node:child_process';
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import PizZip from 'pizzip';

const BUCKET = 'avenida-legal-documents';
const HOME = process.env.USERPROFILE || '.';
const LOCAL_DIR = join(HOME, 'Downloads', 'verify-all-docs');
mkdirSync(LOCAL_DIR, { recursive: true });

function aws(cmd) {
  return execSync(`aws ${cmd} --profile llc-admin --region us-west-1`, { encoding: 'utf8' });
}

// Find newest PLAYWRIGHT QA company folder
const listing = aws(`s3 ls s3://${BUCKET}/ --recursive`);
const playwrightFolders = new Set();
listing.split('\n').forEach((l) => {
  const m = l.match(/\s(playwright-qa-corp-[a-z0-9]+)\//);
  if (m) playwrightFolders.add(m[1]);
});
const folders = [...playwrightFolders].sort();
if (folders.length === 0) {
  console.error('FAIL: no PLAYWRIGHT company folder found in S3');
  process.exit(1);
}
const newestFolder = folders[folders.length - 1];
console.log(`Inspecting folder: ${newestFolder}`);

// List all docs in that folder
const docs = listing.split('\n')
  .filter((l) => l.includes(newestFolder) && /\.(docx|pdf)\s*$/.test(l))
  .map((l) => {
    const parts = l.trim().split(/\s+/);
    return { date: parts[0] + ' ' + parts[1], size: parseInt(parts[2], 10), key: parts.slice(3).join(' ') };
  });

if (docs.length === 0) {
  console.error('FAIL: no docs in that folder');
  process.exit(1);
}

console.log(`Found ${docs.length} documents:\n`);
for (const d of docs) console.log(`  ${d.date}  ${d.size.toString().padStart(8)}  ${d.key}`);
console.log();

const results = [];
for (const d of docs) {
  const name = d.key.split('/').pop();
  const localPath = join(LOCAL_DIR, name);
  try {
    aws(`s3 cp "s3://${BUCKET}/${d.key}" "${localPath}"`);
  } catch (e) {
    results.push({ name, ok: false, reason: 'download failed' });
    continue;
  }

  if (name.endsWith('.pdf')) {
    // Basic: file exists and is non-trivial size
    const size = readFileSync(localPath).length;
    results.push({ name, type: 'pdf', ok: size > 1000, size, notes: size > 1000 ? 'valid size' : 'suspiciously small' });
    continue;
  }

  // DOCX: full structural audit
  const buf = readFileSync(localPath);
  let zip, partNames;
  try {
    zip = new PizZip(buf);
    partNames = Object.keys(zip.files);
  } catch (e) {
    results.push({ name, type: 'docx', ok: false, reason: 'zip parse failed' });
    continue;
  }
  const docXml = zip.file('word/document.xml')?.asText() || '';
  if (!docXml) {
    results.push({ name, type: 'docx', ok: false, reason: 'no document.xml' });
    continue;
  }

  // Aggregate all XML text across styles/theme/document/header/footer
  const allXml = ['word/document.xml', 'word/styles.xml', 'word/theme/theme1.xml']
    .map((p) => zip.file(p)?.asText() || '')
    .join('\n');

  const texts = (docXml.match(/<w:t[^>]*>[^<]*<\/w:t>/g) || [])
    .map((t) => t.replace(/<[^>]+>/g, '')).join('');

  const arialCount = (allXml.match(/Arial/g) || []).length;
  const unresolvedPlaceholders = [...texts.matchAll(/\{\{[a-zA-Z_][\w\s]*\}\}/g)].map((m) => m[0]);
  const bareCounty = (/\bin\s+County,\s*Florida/.test(texts)) || (/\bat\s+County,\s*Florida/.test(texts));
  const thArtifact = /33181th|FL\s+\d{5}\s*th\b/.test(texts);
  const hasCompanyName = /PLAYWRIGHT/i.test(texts);

  const issues = [];
  if (arialCount > 0) issues.push(`${arialCount} Arial refs`);
  if (unresolvedPlaceholders.length) issues.push(`${unresolvedPlaceholders.length} unresolved placeholders: ${unresolvedPlaceholders.slice(0,3).join(',')}${unresolvedPlaceholders.length>3?'...':''}`);
  if (bareCounty) issues.push('bare County/Florida');
  if (thArtifact) issues.push('th artifact');
  if (!hasCompanyName) issues.push('no company name found');

  results.push({
    name, type: 'docx', ok: issues.length === 0,
    size: buf.length,
    arialRefs: arialCount,
    unresolved: unresolvedPlaceholders.length,
    bareCounty,
    thArtifact,
    issues,
  });
}

// Report
console.log('=== AUDIT RESULTS ===\n');
let fails = 0;
for (const r of results) {
  const status = r.ok ? '✓ PASS' : '✗ FAIL';
  console.log(`${status}  ${r.name}`);
  if (r.type === 'docx') {
    console.log(`          size=${r.size}  arial=${r.arialRefs}  unresolved=${r.unresolved}  bareCounty=${r.bareCounty}  th=${r.thArtifact}`);
  } else if (r.type === 'pdf') {
    console.log(`          size=${r.size}  ${r.notes}`);
  }
  if (r.issues?.length) console.log(`          issues: ${r.issues.join('; ')}`);
  if (r.reason) console.log(`          reason: ${r.reason}`);
  if (!r.ok) fails++;
}
console.log();
console.log(`${fails === 0 ? '✓ ALL PASS' : '✗ ' + fails + ' FAIL'} — ${results.length} documents audited`);
console.log(`Local copies: ${LOCAL_DIR}`);
process.exit(fails);
